import json
import os
import subprocess
import time

import pytest

AC_UID = "ac5-task-id-derivation-consistency"
AC_TYPE = "hook"

_REPO = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", ".."))
_HOOKS_DIR = os.path.join(_REPO, "hooks")
_PYTHON = os.path.join(_REPO, "venv", "bin", "python")
if not os.path.isfile(_PYTHON):
    _PYTHON = "python3"


def _make_sentinel(task_id: str, session_id: str) -> str:
    """Write a sentinel grant and return the file path."""
    sentinel_dir = "/tmp/claude-grants"
    os.makedirs(sentinel_dir, exist_ok=True)
    path = os.path.join(sentinel_dir, f"{task_id}.json")
    now = time.time()
    grant = {
        "task_id": task_id,
        "session_id": session_id,
        "allowed_operations": [{"op": "/tmp/xlsx-venv/bin/python"}],
        "created_at": now,
        "expires_at": now + 300,
    }
    with open(path, "w") as f:
        json.dump(grant, f)
    return path


def _run_bash_safety(payload: str, env: dict) -> subprocess.CompletedProcess:
    return subprocess.run(
        ["bash", os.path.join(_HOOKS_DIR, "pretool-bash-safety.sh")],
        input=payload,
        capture_output=True,
        text=True,
        env=env,
        cwd=_HOOKS_DIR,
    )


def test_AC5():
    """
    GIVEN: CLAUDE_TASK_ID env var is unset
    WHEN:  writer (userprompt-consent-allowlist.sh) and reader (pretool-bash-safety.sh) both derive TASK_ID
    THEN:  both resolve to the same string for all four scenarios: (a) CLAUDE_TASK_ID env present: both use it; (b) CLAUDE_TASK_ID unset, PreToolUse JSON task_id field present differing from session_id: both fall back to session_id (mismatch scenario being fixed); (c) only session_id present: both use it; (d) subagent payload: writer exits without writing (Step 0), reader's IS_SUBAGENT=1 path uses same task_id
    """
    cmd = "/tmp/xlsx-venv/bin/python /root/orchestra/docs/dev/find_red_cells.py > /root/orchestra/docs/research/case-3"

    # Scenario (a): CLAUDE_TASK_ID env present — both writer and reader use it
    task_id_a = "ac5-scenario-a-taskid"
    sentinel_path_a = _make_sentinel(task_id_a, task_id_a)
    try:
        env_a = os.environ.copy()
        env_a["CLAUDE_TASK_ID"] = task_id_a
        env_a["CLAUDE_PYTHON_FALLBACK"] = "python3"  # venv symlinks broken in ramdisk env
        env_a.pop("CLAUDE_SESSION_ID", None)
        payload_a = json.dumps({
            "tool_name": "Bash",
            "tool_input": {"command": cmd},
            "agent_id": "ag1",
            "session_id": "ac5-scenario-a-sid",
        })
        proc_a = _run_bash_safety(payload_a, env_a)
        assert proc_a.returncode == 0, f"Scenario (a) failed: {proc_a.stderr}"
        assert "structured grant matched" in proc_a.stderr, f"Scenario (a): grant matched message not found: {proc_a.stderr}"
    finally:
        if os.path.exists(sentinel_path_a):
            os.unlink(sentinel_path_a)

    # Scenario (b): CLAUDE_TASK_ID unset, JSON has task_id != session_id
    # Writer uses session_id; after M3 reader also uses session_id, so both match.
    session_id_b = "ac5-scenario-b-sid"
    task_id_b = "ac5-scenario-b-different-taskid"  # task_id in JSON differs from session_id
    sentinel_path_b = _make_sentinel(session_id_b, session_id_b)  # writer writes under session_id
    try:
        env_b = os.environ.copy()
        env_b.pop("CLAUDE_TASK_ID", None)
        env_b["CLAUDE_PYTHON_FALLBACK"] = "python3"
        env_b.pop("CLAUDE_SESSION_ID", None)
        payload_b = json.dumps({
            "tool_name": "Bash",
            "tool_input": {"command": cmd},
            "agent_id": "ag1",
            "task_id": task_id_b,       # differs from session_id — old reader would use this
            "session_id": session_id_b,
        })
        proc_b = _run_bash_safety(payload_b, env_b)
        assert proc_b.returncode == 0, (
            f"Scenario (b) failed: reader should use session_id='{session_id_b}', "
            f"not task_id='{task_id_b}'\nstderr: {proc_b.stderr}"
        )
        assert "structured grant matched" in proc_b.stderr, (
            f"Scenario (b): grant matched message not found — reader/writer mismatch still present?\n"
            f"stderr: {proc_b.stderr}"
        )
    finally:
        if os.path.exists(sentinel_path_b):
            os.unlink(sentinel_path_b)

    # Scenario (c): CLAUDE_TASK_ID unset, only session_id present in JSON
    session_id_c = "ac5-scenario-c-sid"
    sentinel_path_c = _make_sentinel(session_id_c, session_id_c)
    try:
        env_c = os.environ.copy()
        env_c.pop("CLAUDE_TASK_ID", None)
        env_c["CLAUDE_PYTHON_FALLBACK"] = "python3"
        env_c.pop("CLAUDE_SESSION_ID", None)
        payload_c = json.dumps({
            "tool_name": "Bash",
            "tool_input": {"command": cmd},
            "agent_id": "ag1",
            "session_id": session_id_c,
        })
        proc_c = _run_bash_safety(payload_c, env_c)
        assert proc_c.returncode == 0, f"Scenario (c) failed: {proc_c.stderr}"
        assert "structured grant matched" in proc_c.stderr, f"Scenario (c): grant matched message not found: {proc_c.stderr}"
    finally:
        if os.path.exists(sentinel_path_c):
            os.unlink(sentinel_path_c)

    # Scenario (d): subagent payload — writer exits without writing (Step 0 firewall);
    # reader's IS_SUBAGENT=1 path should still find a pre-existing sentinel under session_id.
    session_id_d = "ac5-scenario-d-sid"
    sentinel_path_d = _make_sentinel(session_id_d, session_id_d)
    try:
        env_d = os.environ.copy()
        env_d.pop("CLAUDE_TASK_ID", None)
        env_d["CLAUDE_PYTHON_FALLBACK"] = "python3"
        env_d.pop("CLAUDE_SESSION_ID", None)
        payload_d = json.dumps({
            "tool_name": "Bash",
            "tool_input": {"command": cmd},
            "agent_id": "ag1",
            "session_id": session_id_d,
        })
        proc_d = _run_bash_safety(payload_d, env_d)
        assert proc_d.returncode == 0, f"Scenario (d) failed: {proc_d.stderr}"
        assert "structured grant matched" in proc_d.stderr, f"Scenario (d): grant matched message not found: {proc_d.stderr}"
    finally:
        if os.path.exists(sentinel_path_d):
            os.unlink(sentinel_path_d)
